    if len(sys.argv) < 3:
        print(f"Usage: {sys.argv[0]} <input_path> <output_path>", file=sys.stderr)
        sys.exit(1)

    input_path = sys.argv[1]
    output_path = sys.argv[2]

    # Load rows
    _, ext = os.path.splitext(input_path.lower())
    if ext == '.csv':
        with open(input_path, 'r', encoding='utf-8-sig', newline='') as f:
            reader = csv.DictReader(f, skipinitialspace=True)
            headers = [h.strip() if h else '' for h in reader.fieldnames] if reader.fieldnames else []
            rows = []
            for r in reader:
                row = {}
                for h, orig_h in zip(headers, reader.fieldnames):
                    val = r.get(orig_h)
                    row[h] = val.strip() if val is not None else ''
                rows.append(row)
    elif ext == '.jsonl':
        with open(input_path, 'r', encoding='utf-8') as f:
            rows = [json.loads(line) for line in f if line.strip()]
            headers = []
            seen = set()
            for r in rows:
                for k in r.keys():
                    if k not in seen:
                        seen.add(k)
                        headers.append(k)
    else:
        print(f"Unsupported input file extension: {ext}", file=sys.stderr)
        sys.exit(1)

