    seen_headers = set(final_headers)
    for r in rows:
        for k in r.keys():
            if k not in seen_headers:
                seen_headers.add(k)
                final_headers.append(k)

    # Write rows
    _, out_ext = os.path.splitext(output_path.lower())
    if out_ext == '.csv':
        with open(output_path, 'w', encoding='utf-8', newline='') as f:
            writer = csv.DictWriter(f, fieldnames=final_headers)
            writer.writeheader()
            for r in rows:
                row_to_write = {h: r.get(h, '') for h in final_headers}
                writer.writerow(row_to_write)
    elif out_ext == '.jsonl':
        with open(output_path, 'w', encoding='utf-8') as f:
            for r in rows:
                f.write(json.dumps(r) + '\n')
    else:
        print(f"Unsupported output file extension: {out_ext}", file=sys.stderr)
        sys.exit(1)

